export const STUDIO_ROUTE_PATTERNS = [
    /^\/studio$/,
    /^\/studio\/experiments$/,
    /^\/studio\/close$/,
    /^\/studio\/sign-in$/,
    /^\/studio\/trace-plan\/[^/]+$/,
    // Matches both real dataset ids and the legacy "labeled" segment; old plugin
    // versions still navigate to /datasets/labeled, which the server redirects.
    /^\/studio\/trace-functions\/[^/]+\/datasets\/[^/]+$/,
    /^\/studio\/trace-functions\/[^/]+\/template-preview$/,
    /^\/studio\/trace-functions\/[^/]+\/template-preview\/[^/]+$/,
    /^\/studio\/auth\/[^/]+$/,
];
export function isValidStudioRoute(input) {
    const pathname = input.split("?")[0];
    return STUDIO_ROUTE_PATTERNS.some((pattern) => pattern.test(pathname));
}
